// Plotly.js vendor placeholder.
//
// STUB. The real bundle (Plotly.js, ~3 MB) exposes window.Plotly with
// Plotly.newPlot(div, data, layout). This placeholder exposes a no-op
// Plotly.newPlot that writes a diagnostic into the target div and warns.
// Replace with the upstream bundle (see README.md) for real plots.

(function () {
  if (typeof window === 'undefined') return;
  if (window.__topoPlotlyPlaceholder) return;
  window.__topoPlotlyPlaceholder = true;
  function warn() {
    if (typeof console !== 'undefined' && console.warn) {
      console.warn(
        '[topo-debug] plotly.min.js is a placeholder. Drop the real ' +
        'Plotly.js bundle at ' +
        'topo-core/lib/Debug/Server/vendor/plotly.min.js to enable ' +
        'scientific plots. See README.md in the same directory.'
      );
    }
  }
  window.Plotly = {
    newPlot: function (el) {
      warn();
      if (el && typeof el === 'object') {
        el.textContent =
          '[plotly placeholder — drop the real bundle to render this plot]';
      }
      return Promise.resolve();
    },
    react: function () { warn(); return Promise.resolve(); },
    purge: function () {}
  };
})();
